import React, { useRef, useEffect, useCallback, useState } from 'react';

// ── Constants ─────────────────────────────────────────────────────────────────
const FIRST_CHUNK   = 2  * 1024 * 1024;  // 2 MB  — fast first frame
const CHUNK         = 20 * 1024 * 1024;  // 20 MB — subsequent chunks
const PREFETCH      = 2;                  // parallel in-flight fetches
const BUF_AHEAD_S   = 30;                // max seconds to buffer ahead
const BUF_BEHIND_S  = 10;                // seconds of buffer to keep behind
const DRIFT_HARD_S  = 0.15;             // hard-correct threshold
const DRIFT_SOFT_S  = 0.05;             // soft-correct threshold (rate nudge)
const SYNC_MS       = 250;              // A/V sync poll interval ms
const MAX_RETRY     = 4;
const RETRY_BASE_MS = 300;
const MIME          = 'video/mp4; codecs="avc1.42E01E,mp4a.40.2"';

const MSE_CAPABLE =
  typeof MediaSource !== 'undefined' && MediaSource.isTypeSupported(MIME);

const sleep = ms => new Promise(r => setTimeout(r, ms));

// ── Probe: Range 206 + fMP4 box scan ─────────────────────────────────────────
async function probeStream(url) {
  try {
    const res = await fetch(url, {
      headers: { Range: 'bytes=0-65535' },
      signal: AbortSignal.timeout(8000),
    });
    if (res.status !== 206) return false;
    const bytes = new Uint8Array(await res.arrayBuffer());
    let off = 0;
    while (off + 8 <= bytes.length) {
      const size =
        (bytes[off] << 24) | (bytes[off+1] << 16) |
        (bytes[off+2] << 8) |  bytes[off+3];
      const type = String.fromCharCode(
        bytes[off+4], bytes[off+5], bytes[off+6], bytes[off+7]);
      if (type === 'moof' || type === 'mvex') return true;
      if (size < 8) break;
      off += size;
    }
    return false;
  } catch { return false; }
}

// ── Fetch helpers ─────────────────────────────────────────────────────────────
async function fetchChunk(url, start, end, signal) {
  for (let i = 0; i <= MAX_RETRY; i++) {
    try {
      const res = await fetch(url, {
        headers: { Range: `bytes=${start}-${end}` },
        signal,
      });
      if (!res.ok && res.status !== 206) throw new Error(`HTTP ${res.status}`);
      return await res.arrayBuffer();
    } catch (e) {
      if (signal.aborted || i === MAX_RETRY) throw e;
      await sleep(RETRY_BASE_MS * 2 ** i);
    }
  }
}

async function getContentLength(url, signal) {
  try {
    const res = await fetch(url, { method: 'HEAD', signal });
    return parseInt(res.headers.get('content-length') || '0', 10);
  } catch { return 0; }
}

// ── MSE Engine ────────────────────────────────────────────────────────────────
// Supports loop: when EOS is reached, resets and re-fetches from byte 0.
class Engine {
  constructor(video, src) {
    this.video    = video;
    this.src      = src;
    this.ms       = new MediaSource();
    this.sb       = null;
    this.total    = 0;
    this.next     = 0;
    this.inflight = 0;
    this.queue    = [];
    this.eos      = false;
    this.dead     = false;
    this.firstBuf = false;
    this.ac       = new AbortController();
    this._url     = URL.createObjectURL(this.ms);
    this.ready    = new Promise(r => { this._resolveReady = r; });
  }

  start() {
    this.video.src = this._url;
    this.ms.addEventListener('sourceopen', () => this._open(), { once: true });
    return this.ready;
  }

  async _open() {
    this.sb = this.ms.addSourceBuffer(MIME);
    this.sb.mode = 'sequence';
    this.sb.addEventListener('updateend', () => this._onUpdateEnd());
    this.total = await getContentLength(this.src, this.ac.signal);
    this._pump();
  }

  _aheadSeconds() {
    const v = this.video, ct = v.currentTime;
    for (let i = 0; i < v.buffered.length; i++) {
      if (v.buffered.start(i) <= ct + 1 && v.buffered.end(i) > ct)
        return v.buffered.end(i) - ct;
    }
    return 0;
  }

  _allFetched() { return this.total > 0 && this.next >= this.total; }

  _pump() {
    if (this.dead || this.eos) return;
    if (this._allFetched()) return;
    if (this._aheadSeconds() >= BUF_AHEAD_S) return;
    while (this.inflight < PREFETCH && !this._allFetched()) this._fetchNext();
  }

  async _fetchNext() {
    const start = this.next;
    const size  = this.firstBuf ? CHUNK : FIRST_CHUNK;
    const end   = this.total
      ? Math.min(start + size - 1, this.total - 1)
      : start + size - 1;
    this.next = end + 1;
    this.inflight++;
    try {
      const buf = await fetchChunk(this.src, start, end, this.ac.signal);
      if (!this.dead) { this.queue.push(buf); this._drain(); }
    } catch (e) {
      if (!this.dead) console.warn('[MSE] fetch error', e);
    } finally {
      this.inflight--;
      if (!this.dead) this._pump();
    }
  }

  _drain() {
    if (!this.sb || this.sb.updating || !this.queue.length) return;
    try { this.sb.appendBuffer(this.queue.shift()); } catch (e) {
      console.warn('[MSE] appendBuffer', e);
    }
  }

  _onUpdateEnd() {
    if (!this.firstBuf) {
      this.firstBuf = true;
      this._resolveReady();
    }
    this._drain();
    this._pump();

    if (this._allFetched() && !this.queue.length && !this.eos) {
      this.eos = true;
      // For loop: listen for 'ended', then reset and re-fetch from start
      this.video.addEventListener('ended', () => this._restart(), { once: true });
      try { if (this.ms.readyState === 'open') this.ms.endOfStream(); } catch {}
    }

    this._evict();
  }

  // Reset engine state and re-fetch from byte 0 for seamless loop
  _restart() {
    if (this.dead) return;
    this.next     = 0;
    this.inflight = 0;
    this.queue    = [];
    this.eos      = false;
    // Re-open MediaSource for the next loop iteration
    if (this.ms.readyState === 'ended') {
      try { this.sb.timestampOffset = 0; } catch {}
    }
    this.video.currentTime = 0;
    this._pump();
    this.video.play().catch(() => {});
  }

  _evict() {
    const v = this.video;
    if (!this.sb || this.sb.updating || !v.buffered.length) return;
    const cutoff = v.currentTime - BUF_BEHIND_S;
    if (cutoff > 0) try { this.sb.remove(0, cutoff); } catch {}
  }

  onTime() { this._pump(); }

  // Seek: align fetch position to the seek point (byte-accurate)
  onSeek() {
    if (!this.total) return;
    const v = this.video;
    // Use buffered ranges to check if seek target is already buffered
    const ct = v.currentTime;
    for (let i = 0; i < v.buffered.length; i++) {
      if (v.buffered.start(i) <= ct && v.buffered.end(i) > ct) return; // already have it
    }
    // Not buffered — reset fetch to byte offset proportional to seek time
    const dur = v.duration;
    const ratio = (dur && isFinite(dur)) ? ct / dur : 0;
    const bytePos = Math.floor(ratio * this.total);
    this.next     = Math.floor(bytePos / CHUNK) * CHUNK;
    this.inflight = 0;
    this.queue    = [];
    this.eos      = false;
    this._pump();
  }

  destroy() {
    this.dead = true;
    this.sb   = null;
    this.ac.abort();
    try { if (this.ms.readyState === 'open') this.ms.endOfStream(); } catch {}
    URL.revokeObjectURL(this._url);
  }
}

// ── A/V Sync controller ───────────────────────────────────────────────────────
class AVSync {
  constructor(video, audio) {
    this.video   = video;
    this.audio   = audio;
    this._timer  = null;
    this._paused = false; // true while we're waiting for audio to recover
  }

  start() {
    this.stop();
    this._timer = setInterval(() => this._tick(), SYNC_MS);
    this.video.addEventListener('seeked',  this._onSeeked);
    this.audio.addEventListener('waiting', this._onAudioWaiting);
    this.video.addEventListener('waiting', this._onVideoWaiting);
  }

  stop() {
    clearInterval(this._timer);
    this._timer = null;
    this.video.removeEventListener('seeked',  this._onSeeked);
    this.audio.removeEventListener('waiting', this._onAudioWaiting);
    this.video.removeEventListener('waiting', this._onVideoWaiting);
  }

  _tick() {
    const { video: v, audio: a } = this;
    if (!v || !a || v.paused || a.paused || this._paused) return;
    const drift = v.currentTime - a.currentTime;
    if (Math.abs(drift) > DRIFT_HARD_S) {
      a.currentTime = v.currentTime;
    } else if (Math.abs(drift) > DRIFT_SOFT_S) {
      a.playbackRate = drift > 0 ? 1.04 : 0.96;
    } else {
      a.playbackRate = 1.0;
    }
  }

  _onSeeked = () => {
    const { video: v, audio: a } = this;
    if (!v || !a) return;
    a.currentTime = v.currentTime;
  };

  // Audio stalled: pause video, wait for audio canplay, then re-sync
  _onAudioWaiting = () => {
    const { video: v, audio: a } = this;
    if (!v || !a || this._paused) return;
    this._paused = true;
    v.pause();
    const resume = () => {
      this._paused = false;
      a.currentTime = v.currentTime;
      v.play().catch(() => {});
    };
    a.addEventListener('canplay', resume, { once: true });
  };

  // Video stalled (MSE buffering): pause audio to stay in sync
  _onVideoWaiting = () => {
    const { video: v, audio: a } = this;
    if (!v || !a || this._paused) return;
    this._paused = true;
    a.pause();
    const resume = () => {
      this._paused = false;
      a.currentTime = v.currentTime;
      a.play().catch(() => {});
    };
    v.addEventListener('canplay', resume, { once: true });
  };
}

// ── Component ─────────────────────────────────────────────────────────────────
// Props:
//   src       — video URL (fMP4)
//   audioSrc  — audio URL (mp3); if omitted, falls back to regex derivation
//   id        — unique card id
//   activeAudioId / onVisibilityChange — from parent
const VideoAudioPlayer = ({ src, audioSrc: audioSrcProp, id, activeAudioId, onVisibilityChange }) => {
  const videoRef = useRef(null);
  const audioRef = useRef(null);
  const boxRef   = useRef(null);
  const engRef   = useRef(null);
  const syncRef  = useRef(null);
  const [mode, setMode] = useState(null); // null=probing | true=MSE | false=native

  const isActive = activeAudioId === id;

  // Explicit audioSrc prop takes priority; fallback: strip _fmp4 + change ext
  const audioSrc = audioSrcProp ||
    src.replace(/(_fmp4)?\.(mp4|webm)(\?.*)?$/i, '.mp3$3');

  // ── Probe once per src ──────────────────────────────────────────────────────
  useEffect(() => {
    if (!MSE_CAPABLE) { setMode(false); return; }
    let live = true;
    probeStream(src).then(ok => { if (live) setMode(ok); });
    return () => { live = false; };
  }, [src]);

  // ── Bootstrap video when mode is resolved ───────────────────────────────────
  useEffect(() => {
    if (mode === null) return;
    const video = videoRef.current;
    if (!video) return;

    if (mode) {
      const eng = new Engine(video, src);
      engRef.current = eng;

      const onErr = () => { eng.destroy(); engRef.current = null; setMode(false); };
      const onTime = () => eng.onTime();
      const onSeek = () => eng.onSeek();

      video.addEventListener('error',      onErr, { once: true });
      video.addEventListener('timeupdate', onTime);
      video.addEventListener('seeking',    onSeek);

      eng.start().then(() => { video.play().catch(() => {}); });

      return () => {
        video.removeEventListener('error',      onErr);
        video.removeEventListener('timeupdate', onTime);
        video.removeEventListener('seeking',    onSeek);
        eng.destroy();
        engRef.current = null;
      };
    } else {
      video.src = src;
      video.play().catch(() => {});
      return () => { video.src = ''; };
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, src]);

  // ── A/V sync: start/stop when card becomes active ──────────────────────────
  useEffect(() => {
    const v = videoRef.current;
    const a = audioRef.current;
    if (!v || !a) return;

    if (isActive) {
      a.currentTime = v.currentTime;
      a.play().catch(() => {});
      const sync = new AVSync(v, a);
      syncRef.current = sync;
      sync.start();
    } else {
      a.pause();
      if (syncRef.current) { syncRef.current.stop(); syncRef.current = null; }
    }

    return () => {
      if (syncRef.current) { syncRef.current.stop(); syncRef.current = null; }
    };
  }, [isActive]);

  // ── Intersection observer ───────────────────────────────────────────────────
  const handleVisibility = useCallback(
    ([entry]) => onVisibilityChange(id, entry.isIntersecting && entry.intersectionRatio > 0.5),
    [id, onVisibilityChange]
  );

  useEffect(() => {
    const el = boxRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(handleVisibility, { threshold: 0.5 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [handleVisibility]);

  return (
    <div ref={boxRef} style={{ overflowAnchor: 'none' }}>
      <video
        ref={videoRef}
        autoPlay
        loop
        muted
        playsInline
        style={{ width: '100%', height: 'auto', display: 'block' }}
      />
      <audio
        ref={audioRef}
        src={audioSrc}
        loop
        preload="auto"
        style={{ position: 'absolute', left: '-9999px' }}
        tabIndex="-1"
      />
    </div>
  );
};

export default VideoAudioPlayer;
